export default class NotFound extends HTMLElement{static props={};constructor(props){super(),slice.attachTemplate(this),slice.controller.setComponentProps(this,props)}async init(){document.title="404 - Not Found";const o=this.querySelector(".home-btn-container");if(o){const t=await slice.build("Button",{value:"Go Home",customColor:{background:"var(--primary-color-contrast)",text:"var(--primary-color)"},o:()=>slice.router.navigate("/")});o.appendChild(t)}}}customElements.define("slice-notfound",NotFound);